// ===== LALAO VONONA - GAME KITS =====
t.LalaoVonona = {
    "flappy": (kianja) => {
        let vorona = new t.MpandrayAnjara(kianja, 100, 300, null);
        vorona.sakany = 34; vorona.haavony = 24; vorona.fizika("mandeha");
        vorona.loko = "#FFD700";
        vorona.havaozyKoa = (dt) => {
            vorona.vx = 120;
            if (Rakitrakatra.KitendryVao("space")) vorona.vy = -400;
            kianja.fakanTsary.manaraka = vorona;
        };
        vorona.soraty = (ctx) => {
            ctx.fillStyle = vorona.loko;
            ctx.beginPath(); ctx.ellipse(vorona.x, vorona.y, 17, 12, 0, 0, Math.PI*2); ctx.fill();
        };
        setInterval(() => {
            let haavo = Rakitrakatra.Util.kisendrasendra(100, 400);
            let ambony = new t.MpandrayAnjara(kianja, vorona.x + 400, 0, null);
            ambony.sakany = 60; ambony.haavony = haavo; ambony.loko = "#228B22"; ambony.mijanona = true;
            let ambany = new t.MpandrayAnjara(kianja, vorona.x + 400, haavo + 150, null);
            ambany.sakany = 60; ambany.haavony = 600; ambany.loko = "#228B22"; ambany.mijanona = true;
            ambony.ampioMifandona(() => Rakitrakatra.mandehana("Tapitra"));
            ambany.ampioMifandona(() => Rakitrakatra.mandehana("Tapitra"));
        }, 1500);
    },
    "breakout": (kianja) => {
        let baolina = new t.MpandrayAnjara(kianja, 400, 300, null);
        baolina.sakany = 16; baolina.haavony = 16; baolina.fizika("mandeha");
        baolina.vx = 200; baolina.vy = -300; baolina.fikitihana = 1; baolina.loko = "#FFF";
        let fantsona = new t.MpandrayAnjara(kianja, 350, 550, null);
        fantsona.sakany = 100; fantsona.haavony = 20; fantsona.mijanona = true; fantsona.loko = "#00F";
        fantsona.havaozyKoa = () => {
            if (Rakitrakatra.Kitendry("havanana")) fantsona.x += 400 * (1/60);
            if (Rakitrakatra.Kitendry("ankavia")) fantsona.x -= 400 * (1/60);
        };
        for(let y=0; y<5; y++) for(let x=0; x<10; x++) {
            let biriky = new t.MpandrayAnjara(kianja, 80 + x*65, 50 + y*30, null);
            biriky.sakany = 60; biriky.haavony = 25; biriky.mijanona = true;
            biriky.loko = `hsl(${y*60}, 100%, 50%)`;
            biriky.ampioMifandona(() => {
                biriky.fafao();
                new t.Vovoka(kianja, biriky.x, biriky.y, {isany: 15, hafainganam: 200, andromPiainana: 500, loko: biriky.loko, habe: {fanombohana: 3, fiafarana: 0}});
            });
        }
    }
};

// ===== TAZOHO - ROPE & JOINTS =====
t.Tazaho = class {
    constructor(kianja, z1, z2, halavana) {
        this.z1 = z1; this.z2 = z2; this.halavana = halavana;
        kianja.zavatra.push(this);
    }
    havaozy(dt) {
        let dx = this.z2.x - this.z1.x, dy = this.z2.y - this.z1.y;
        let elanelana = Math.hypot(dx, dy);
        if (elanelana > this.halavana) {
            let hery = (elanelana - this.halavana) * 5;
            let nx = dx / elanelana, ny = dy / elanelana;
            this.z1.vx += nx * hery * dt; this.z1.vy += ny * hery * dt;
            this.z2.vx -= nx * hery * dt; this.z2.vy -= ny * hery * dt;
        }
    }
    soraty(ctx) {
        ctx.strokeStyle = "#8B4513"; ctx.lineWidth = 3;
        ctx.beginPath(); ctx.moveTo(this.z1.x, this.z1.y); ctx.lineTo(this.z2.x, this.z2.y); ctx.stroke();
    }
};

// ===== RIHANA - FORCE FIELDS =====
t.Rihana = class {
    constructor(kianja, karazana, f) {
        this.karazana = karazana; this.hery = f.hery || 300;
        this.x = f.x || 0; this.y = f.y || 0; this.sakany = f.sakany || 800; this.haavony = f.haavony || 600;
        kianja.zavatra.push(this);
    }
    havaozy(dt) {
        this.kianja.zavatra.forEach(z => {
            if (z instanceof t.MpandrayAnjara && z.mavita && z.x > this.x && z.x < this.x + this.sakany) {
                if (this.karazana === "rivotra") z.vx += this.hery * dt;
                if (this.karazana === "rano") { z.vy *= 0.5; z.vy -= this.hery * dt; }
                if (this.karazana === "andriamby") {
                    let dx = (this.x + this.sakany/2) - z.x, dy = (this.y + this.haavony/2) - z.y;
                    let d = Math.hypot(dx, dy); z.vx += (dx/d) * this.hery * dt; z.vy += (dy/d) * this.hery * dt;
                }
            }
        });
    }
    soraty() {}
};

// ===== VOKATRA.SARINY - SPRITE FX =====
t.Vokatra = {
    "mamirapiratra": (z) => { z._glow = 10; z.soraty = function(ctx) {
        ctx.save(); ctx.shadowColor = "#FFD700"; ctx.shadowBlur = this._glow;
        t.MpandrayAnjara.prototype.soraty.call(this, ctx); ctx.restore();
    }},
    "mihozongozona": (z) => { z._hery = 5; z.havaozyKoa = function(dt) {
        this.x += (Math.random()-0.5) * this._hery; this.y += (Math.random()-0.5) * this._hery;
    }},
    "manjavona": (z) => { z._alpha = 1; z.havaozyKoa = function(dt) {
        this._alpha -= dt; if (this._alpha <= 0) this.fafao();
    }}
};
s.prototype.vokatra = function(anarana) { t.Vokatra[anarana]?.(this); };

// ===== HOSODOKO.KAODY - PROCEDURAL ART =====
t.Hosodoko = {
    "hazo": (s, h) => {
        let c = document.createElement('canvas'); c.width = s; c.height = h;
        let ctx = c.getContext('2d');
        ctx.fillStyle = "#8B4513"; ctx.fillRect(s*0.4, h*0.5, s*0.2, h*0.5);
        ctx.fillStyle = "#228B22"; ctx.beginPath(); ctx.arc(s/2, h*0.4, s*0.4, 0, Math.PI*2); ctx.fill();
        return c.toDataURL();
    },
    "vato": (s, h) => {
        let c = document.createElement('canvas'); c.width = s; c.height = h;
        let ctx = c.getContext('2d'); ctx.fillStyle = "#808080";
        ctx.beginPath(); ctx.moveTo(s*0.2, h*0.8); ctx.lineTo(s*0.1, h*0.5);
        ctx.lineTo(s*0.5, h*0.2); ctx.lineTo(s*0.9, h*0.6); ctx.lineTo(s*0.8, h*0.9); ctx.closePath(); ctx.fill();
        return c.toDataURL();
    }
};

// ===== FEO.MAMORONA - SYNTH SFX =====
t.Feo.mamorona = (karazana) => {
    let ctx = new (window.AudioContext || window.webkitAudioContext)();
    let o = ctx.createOscillator(), g = ctx.createGain();
    o.connect(g); g.connect(ctx.destination);
    if (karazana === "jump") { o.frequency.value = 400; g.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.2); }
    if (karazana === "coin") { o.frequency.value = 800; o.frequency.exponentialRampToValueAtTime(1200, ctx.currentTime + 0.1); g.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.1); }
    if (karazana === "poa") { o.type = "sawtooth"; o.frequency.value = 100; o.frequency.exponentialRampToValueAtTime(50, ctx.currentTime + 0.3); g.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.3); }
    o.start(); o.stop(ctx.currentTime + 0.5);
};

// ===== FIKITIHANA.GASY - MOBILE =====
t.Fikitihana = { swipe: (tari) => {}, pinch: (f) => {} };
document.addEventListener('touchstart', e => { t.Fikitihana._fanombohana = e.touches[0]; });
document.addEventListener('touchend', e => {
    if (!t.Fikitihana._fanombohana) return;
    let dx = e.changedTouches[0].clientX - t.Fikitihana._fanombohana.clientX;
    let dy = e.changedTouches[0].clientY - t.Fikitihana._fanombohana.clientY;
    if (Math.abs(dx) > Math.abs(dy)) {
        if (dx > 50) t.Fikitihana.swipe["havanana"]?.();
        if (dx < -50) t.Fikitihana.swipe["ankavia"]?.();
    } else {
        if (dy > 50) t.Fikitihana.swipe["ambany"]?.();
        if (dy < -50) t.Fikitihana.swipe["ambony"]?.();
    }
});

